import{_ as t,o,c as a,a2 as s}from"./chunks/framework.CuteRReP.js";const g=JSON.parse('{"title":"Brainstorm Output: cm-dashboard Task Bridge","description":"","frontmatter":{},"headers":[],"relativePath":"brainstorm/cm-dashboard-task-bridge.md","filePath":"brainstorm/cm-dashboard-task-bridge.md"}'),r={name:"brainstorm/cm-dashboard-task-bridge.md"};function i(n,e,l,d,c,u){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="brainstorm-output-cm-dashboard-task-bridge" tabindex="-1">Brainstorm Output: cm-dashboard Task Bridge <a class="header-anchor" href="#brainstorm-output-cm-dashboard-task-bridge" aria-label="Permalink to &quot;Brainstorm Output: cm-dashboard Task Bridge&quot;">​</a></h1><p>Generated by: cm-brainstorm-idea Date: 2026-03-23</p><h2 id="initiative" tabindex="-1">Initiative <a class="header-anchor" href="#initiative" aria-label="Permalink to &quot;Initiative&quot;">​</a></h2><p>Upgrade <code>cm-dashboard</code> skill so that tasks from Claude Code (TodoWrite) and Claude Desktop automatically appear on the dashboard — no manual entry.</p><p>Also researched: <a href="https://github.com/terranc/claude-telegram-bot-bridge" target="_blank" rel="noreferrer">https://github.com/terranc/claude-telegram-bot-bridge</a></p><h2 id="qualified-problem" tabindex="-1">Qualified Problem <a class="header-anchor" href="#qualified-problem" aria-label="Permalink to &quot;Qualified Problem&quot;">​</a></h2><p><strong>For:</strong> Developers using Cody Master with multiple AI agents (Claude Code, Claude Desktop, etc.) <strong>Who:</strong> Cannot see real-time task progress across sessions without manually updating the board <strong>The:</strong> cm-dashboard lacks automatic bridges to Claude Code TodoWrite events and Claude Desktop <strong>That:</strong> Should reflect live task state from all agents without any manual action <strong>Unlike:</strong> Current state where the board is a static, manually-curated kanban <strong>Our approach:</strong> Wire existing hooks + MCP infrastructure to push tasks automatically to the dashboard</p><p><strong>Root causes:</strong></p><ol><li><code>PostToolUse</code> hook for <code>TodoWrite</code> is never configured in settings.json</li><li>No MCP server exists for Claude Desktop (which has no hooks system)</li><li>SKILL.md documents no auto-sync setup instructions</li></ol><p><strong>Impact if NOT addressed:</strong></p><ul><li>Dashboard remains a manual tool, negating the &quot;single pane of glass&quot; promise</li><li>Developers must duplicate work: track in conversation AND move cards manually</li><li>Multi-agent coordination is invisible</li></ul><h2 id="_9-windows-summary" tabindex="-1">9 Windows Summary <a class="header-anchor" href="#_9-windows-summary" aria-label="Permalink to &quot;9 Windows Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>PAST</th><th>PRESENT</th><th>FUTURE</th></tr></thead><tbody><tr><td>Super-system</td><td>Todos = local dev habit, no cross-tool sync</td><td>Multi-agent → tasks live in silos</td><td>Unified ops across all AI agents expected</td></tr><tr><td>System</td><td>Dashboard = manual board</td><td>15s poll, no auto-sync from agents</td><td>Dashboard = live task hub synced to all sources</td></tr><tr><td>Sub-system</td><td>Tasks created by hand</td><td>auto-sync API exists, hooks not wired</td><td>Hooks + MCP bridge runs transparently</td></tr></tbody></table><h2 id="options-evaluated" tabindex="-1">Options Evaluated <a class="header-anchor" href="#options-evaluated" aria-label="Permalink to &quot;Options Evaluated&quot;">​</a></h2><h3 id="option-a-hooks-only-bridge-claude-code" tabindex="-1">Option A: Hooks-Only Bridge (Claude Code) <a class="header-anchor" href="#option-a-hooks-only-bridge-claude-code" aria-label="Permalink to &quot;Option A: Hooks-Only Bridge (Claude Code)&quot;">​</a></h3><ul><li>PostToolUse hook → shell/JS script → POST /api/tasks/auto-sync</li><li><strong>Effort:</strong> S (~2-3h) | <strong>Risk:</strong> Low</li><li><strong>Score:</strong> 8.0/10</li></ul><h3 id="option-b-mcp-server-bridge-universal" tabindex="-1">Option B: MCP Server Bridge (Universal) <a class="header-anchor" href="#option-b-mcp-server-bridge-universal" aria-label="Permalink to &quot;Option B: MCP Server Bridge (Universal)&quot;">​</a></h3><ul><li>New MCP server wrapping dashboard API, mounted in both CC and Desktop</li><li><strong>Effort:</strong> M (~6-8h) | <strong>Risk:</strong> Medium</li><li><strong>Score:</strong> 7.6/10</li></ul><h3 id="option-c-telegram-style-daemon" tabindex="-1">Option C: Telegram-Style Daemon <a class="header-anchor" href="#option-c-telegram-style-daemon" aria-label="Permalink to &quot;Option C: Telegram-Style Daemon&quot;">​</a></h3><ul><li>Background daemon parsing subprocess stdout, inspired by claude-telegram-bot-bridge</li><li><strong>Effort:</strong> XL (~2-3 days) | <strong>Risk:</strong> High (fragile)</li><li><strong>Score:</strong> 5.1/10</li></ul><h2 id="recommendation" tabindex="-1">Recommendation <a class="header-anchor" href="#recommendation" aria-label="Permalink to &quot;Recommendation&quot;">​</a></h2><p><strong>Hybrid A+B — implement in sequence:</strong></p><ol><li><p><strong>Phase 1 (Ship first):</strong> Hooks bridge for Claude Code</p><ul><li>New <code>scripts/todo-bridge.js</code></li><li>Settings.json hook config: matcher=TodoWrite, PostToolUse</li><li>Reuses existing <code>/api/tasks/auto-sync</code> endpoint</li><li>Auto-detects projectId from session working directory</li></ul></li><li><p><strong>Phase 2 (Claude Desktop):</strong> MCP server</p><ul><li>New <code>src/mcp-bridge.ts</code></li><li>Tools: <code>sync_tasks(todos[])</code>, <code>update_task(id, status)</code>, <code>get_tasks(projectId)</code></li><li>Claude Desktop mounts via claude_desktop_config.json</li></ul></li></ol><h2 id="key-technical-insights-from-telegram-bot-research" tabindex="-1">Key Technical Insights from Telegram Bot Research <a class="header-anchor" href="#key-technical-insights-from-telegram-bot-research" aria-label="Permalink to &quot;Key Technical Insights from Telegram Bot Research&quot;">​</a></h2><p>The <code>claude-telegram-bot-bridge</code> uses:</p><ul><li>Python subprocess → Claude CLI → long-poll pattern</li><li>SESSION_ROOT sandbox for file access</li><li>launchd integration for daemon persistence</li></ul><p><strong>Applicable to future work:</strong> If we ever want remote dashboard control from mobile/Telegram, this is the pattern. Not needed for current task sync initiative.</p><h2 id="next-steps-for-cm-planning" tabindex="-1">Next Steps for cm-planning <a class="header-anchor" href="#next-steps-for-cm-planning" aria-label="Permalink to &quot;Next Steps for cm-planning&quot;">​</a></h2><ol><li><strong>Scope:</strong> Build todo-bridge.js + settings.json hook config + SKILL.md upgrade</li><li><strong>Constraints:</strong><ul><li>Must reuse <code>/api/tasks/auto-sync</code> — no new endpoints needed</li><li>Bridge script must be installable to <code>~/.claude/</code> (not project-specific)</li><li>No breaking changes to current dashboard UI or API</li></ul></li><li><strong>Technical decisions already made:</strong> D005 in decisions.json</li><li><strong>Open questions:</strong><ul><li>Bridge script in JS (Node) or shell? JS preferred (easier JSON parsing)</li><li>MCP server — separate npm package or bundled in <code>dist/</code>?</li><li>Should TodoWrite deletions propagate to dashboard?</li></ul></li></ol><h2 id="context-for-downstream-skills" tabindex="-1">Context for downstream skills <a class="header-anchor" href="#context-for-downstream-skills" aria-label="Permalink to &quot;Context for downstream skills&quot;">​</a></h2><ul><li><strong>cm-planning:</strong> Focus on Phase 1 first (hooks bridge). Plan 3 files: todo-bridge.js, settings-hook-snippet.json, updated SKILL.md</li><li><strong>cm-tdd:</strong> Test that auto-sync endpoint correctly upserts by conversationId and maps todo status to task columns</li><li><strong>cm-execution:</strong> Each phase is independent — can be dispatched as separate worktree tasks</li></ul>',31)])])}const p=t(r,[["render",i]]);export{g as __pageData,p as default};
